import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.stream.ActorMaterializer
import com.typesafe.config.ConfigFactory

import scala.concurrent.duration._

object WebhookProxyService {
  def main(args: Array[String]): Unit = {
    implicit val system = ActorSystem("webhook-proxy")
    implicit val materializer = ActorMaterializer()
    implicit val executionContext = system.dispatcher

    val config = ConfigFactory.load()

    val allowedDestinations = config.getStringList("allowed-destinations").toList
    val blockedIpRanges = config.getStringList("blocked-ip-ranges").map(_.split("-")).map {
      case Array(start, end) => (start, end)
    }.toSet

    val route =
      path("webhook") {
        post {
          entity(as[String]) { userUrl =>
            val ip = request.remoteAddress.get
            if (!blockedIpRanges.exists(range => range._1 <= ip && ip <= range._2)) {
              val allowed = allowedDestinations.contains(userUrl)
              if (allowed) {
                val responseFuture = Http().singleRequest(HttpRequest(uri = userUrl))
                responseFuture.map { response =>
                  complete(response)
                }.recover {
                  case e: Exception => complete(StatusCodes.InternalServerError, s"Error fetching content from $userUrl")
                }
              } else {
                complete(StatusCodes.Forbidden, "Forbidden destination")
              }
            } else {
              complete(StatusCodes.Forbidden, "Blocked IP range")
            }
          }
        }
      }

    val bindingFuture = Http().bindAndHandle(route, "localhost", 8080)
    println(s"Server online at http://localhost:8080/webhook")
  }
}